from machine import Pin
import time
import umqttsimple

sensorPin = machine.Pin(4,machine.Pin.IN)
clientID = "ESP32" # Use your unique ID here
brokerIP = "localhost" 
brokerPort = 1883
tempReadDelay = 5000
mqttClient = umqttsimple.MQTTClient(clientID, brokerIP, brokerPort)

# Connect to the Broker and print some info
mqttClient.connect()
print("Connected to ",brokerIP)

while True:
  # Read Temperature
  tempSensorVal = sensorPin.value() * 3.41 / 250; 

  # Publish temperature to broker 
  mqttClient.publish("sensors/temp",str(tempSensorVal),True)
  print('temperature value',str(tempSensorVal))

  time.sleep_ms(tempReadDelay)